def insert_key_map(key, key_map, op_type, key_start, key_end, txn_id):
    index = len(key_map[key]) - 1
    for op in key_map[key]:
        (_, s, e, _) = key_map[key][index]
        if e <= key_end:
            if s <= key_start:
                index += 1
                break
        elif s <= key_start:
            index += 1
            break
        index -= 1
