                    key_start = key_map[key][-1][2] + 1
                else:
                    key_start = find_earliest_read(key, key_map, txn_id)
                needed = key_start - pos + 1
                if needed > txn_start:
                    txn_start = needed
            txn_total_len = txn_len

        txn_end = txn_start + txn_total_len - 1
        cost = txn_end - total_cost
        if txn_end <= total_cost:
            cost = 0
        total_cost += cost

        for j in range(len(txn)):
            (op_type, key, pos, txn_len) = txn[j]
            key_start_actual = txn_start + pos - 1
            if key in key_map:
                insert_key_map(key, key_map, op_type, key_start_actual, key_start_actual, txn_id)
            else:
                key_map[key] = [(op_type, key_start_actual, key_start_actual, txn_id)]

        txn_id += 1

    return total_cost

